mapper.select:
/*ReplaceUsimMapper.selectFreeUsimSettings*/
SELECT DTL_CD_NM
FROM NMCP_CD_DTL
WHERE CD_GROUP_ID = 'FreeUsimSettings'
  AND DTL_CD = #{dtlCd}

/*ReplaceUsimMapper.generateReplaceUsimOsstNo*/
SELECT DECODE(NVL(OSST_NO, 0), 0, SQ_FREE_USIM_OSST.NEXTVAL, OSST_NO) AS OSST_NO
FROM NMCP_FREE_USIM_REQ_MST
WHERE SEQ = #{seq}

mapper.update:
/*ReplaceUsimMapper.updateFreeUsimReqDtl*/
UPDATE NMCP_FREE_USIM_REQ_DTL
SET APPLY_RSLT_CD = #{applyRsltCd}
   ,APPLY_RSLT_MSG = DECODE(#{applyRsltCd}, '00', '처리성공', #{applyRsltMsg})
   ,AMD_ID = 'MCP_BATCH'
   ,AMD_DTTM = SYSDATE
WHERE SEQ = #{seq}
  AND SUB_SEQ = #{subSeq}
  AND APPLY_RSLT_CD IS NULL

/*ReplaceUsimMapper.updateFreeUsimReqMst*/
UPDATE NMCP_FREE_USIM_REQ_MST
SET OSST_NO = #{osstNo}
   ,AMD_ID = 'MCP_BATCH'
   ,AMD_DTTM = SYSDATE
WHERE SEQ = #{seq}
